const w = $input.first().json;
const city = w.name || $env.WEATHER_CITY || 'Stadt';
const temp = Math.round(w.main?.temp || 0);
const feelsLike = Math.round(w.main?.feels_like || 0);
const desc = w.weather?.[0]?.description || 'unbekannt';
const windKmh = Math.round((w.wind?.speed || 0) * 3.6);
const humidity = w.main?.humidity || 0;
const rain = w.rain?.['1h'] || 0;
const snow = w.snow?.['1h'] || 0;
const weatherId = w.weather?.[0]?.id || 800;

// Warnung bestimmen
let warning = null;
let priority = 'low';

if (weatherId >= 200 && weatherId < 300) { warning = 'Gewitter'; priority = 'high'; }
else if (weatherId >= 600 && weatherId < 700) { warning = 'Schneefall'; priority = 'medium'; }
else if (rain > 5) { warning = 'Starkregen'; priority = 'medium'; }
else if (windKmh > 60) { warning = 'Sturmwind'; priority = 'high'; }
else if (temp < -5) { warning = 'Starker Frost'; priority = 'high'; }
else if (temp < 0) { warning = 'Frost'; priority = 'medium'; }
else if (temp > 35) { warning = 'Extreme Hitze'; priority = 'high'; }

const summaryParts = [`Wetter in ${city}: ${desc}, ${temp}°C`];
if (warning) summaryParts.push(`⚠️ ${warning}`);
if (rain > 0) summaryParts.push(`Regen ${rain}mm/h`);

return [{
  json: {
    source: 'weather',
    source_id: `weather-${city}-${new Date().toISOString().slice(0,13)}`,
    summary: summaryParts.join(' — '),
    priority: priority,
    customer_id: $env.CUSTOMER_ID || null,
    buddy_id: $env.BUDDY_ID || null,
    timestamp: new Date().toISOString(),
    details: {
      city: city,
      temperature_c: temp,
      feels_like_c: feelsLike,
      condition: desc,
      warning_level: priority === 'high' ? 'red' : priority === 'medium' ? 'yellow' : 'green',
      warning: warning,
      wind_kmh: windKmh,
      humidity_pct: humidity,
      rain_mm_h: rain,
      snow_mm_h: snow
    }
  }
}];

